import{_ as o,o as a,c as i,ai as t}from"./chunks/framework.CsYGeNYI.js";const p=JSON.parse('{"title":"Onboarding Wizard Reference","description":"","frontmatter":{"summary":"Full reference for the CLI onboarding wizard: every step, flag, and config field","read_when":["Looking up a specific wizard step or flag","Automating onboarding with non-interactive mode","Debugging wizard behavior"],"title":"Onboarding Wizard Reference","sidebarTitle":"Wizard Reference"},"headers":[],"relativePath":"reference/wizard.md","filePath":"reference/wizard.md","lastUpdated":null}'),s={name:"reference/wizard.md"};function n(l,e,r,d,c,h){return a(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="onboarding-wizard-reference" tabindex="-1"><a class="header-anchor" href="#onboarding-wizard-reference">#</a> Onboarding Wizard Reference</h1><p>This is the full reference for the <code>opensoul onboard</code> CLI wizard. For a high-level overview, see <a href="/docs/start/wizard">Onboarding Wizard</a>.</p><h2 id="flow-details-local-mode" tabindex="-1"><a class="header-anchor" href="#flow-details-local-mode">#</a> Flow details (local mode)</h2><h3 id="existing-config-detection" tabindex="-1"><a class="header-anchor" href="#existing-config-detection">#</a> Existing config detection</h3><ul><li>If <code>~/.opensoul/opensoul.json</code> exists, choose <strong>Keep / Modify / Reset</strong>.</li><li>Re-running the wizard does <strong>not</strong> wipe anything unless you explicitly choose <strong>Reset</strong> (or pass <code>--reset</code>).</li><li>If the config is invalid or contains legacy keys, the wizard stops and asks you to run <code>opensoul doctor</code> before continuing.</li><li>Reset uses <code>trash</code> (never <code>rm</code>) and offers scopes: <ul><li>Config only</li><li>Config + credentials + sessions</li><li>Full reset (also removes workspace)</li></ul></li></ul><h3 id="model-auth" tabindex="-1"><a class="header-anchor" href="#model-auth">#</a> Model/Auth</h3><ul><li><strong>Anthropic API key (recommended)</strong>: uses <code>ANTHROPIC_API_KEY</code> if present or prompts for a key, then saves it for daemon use.</li><li><strong>Anthropic OAuth (Claude Code CLI)</strong>: on macOS the wizard checks Keychain item &quot;Claude Code-credentials&quot; (choose &quot;Always Allow&quot; so launchd starts don&#39;t block); on Linux/Windows it reuses <code>~/.claude/.credentials.json</code> if present.</li><li><strong>Anthropic token (paste setup-token)</strong>: run <code>claude setup-token</code> on any machine, then paste the token (you can name it; blank = default).</li><li><strong>OpenAI Code (Codex) subscription (Codex CLI)</strong>: if <code>~/.codex/auth.json</code> exists, the wizard can reuse it.</li><li><strong>OpenAI Code (Codex) subscription (OAuth)</strong>: browser flow; paste the <code>code#state</code>. <ul><li>Sets <code>agents.defaults.model</code> to <code>openai-codex/gpt-5.2</code> when model is unset or <code>openai/*</code>.</li></ul></li><li><strong>OpenAI API key</strong>: uses <code>OPENAI_API_KEY</code> if present or prompts for a key, then saves it to <code>~/.opensoul/.env</code> so launchd can read it.</li><li><strong>xAI (Grok) API key</strong>: prompts for <code>XAI_API_KEY</code> and configures xAI as a model provider.</li><li><strong>OpenCode Zen (multi-model proxy)</strong>: prompts for <code>OPENCODE_API_KEY</code> (or <code>OPENCODE_ZEN_API_KEY</code>, get it at <a href="https://opencode.ai/auth" target="_blank" rel="noreferrer">https://opencode.ai/auth</a>).</li><li><strong>API key</strong>: stores the key for you.</li><li><strong>Vercel AI Gateway (multi-model proxy)</strong>: prompts for <code>AI_GATEWAY_API_KEY</code>.</li><li>More detail: <a href="/docs/providers/vercel-ai-gateway">Vercel AI Gateway</a></li><li><strong>Cloudflare AI Gateway</strong>: prompts for Account ID, Gateway ID, and <code>CLOUDFLARE_AI_GATEWAY_API_KEY</code>.</li><li>More detail: <a href="/docs/providers/cloudflare-ai-gateway">Cloudflare AI Gateway</a></li><li><strong>MiniMax M2.1</strong>: config is auto-written.</li><li>More detail: <a href="/docs/providers/minimax">MiniMax</a></li><li><strong>Synthetic (Anthropic-compatible)</strong>: prompts for <code>SYNTHETIC_API_KEY</code>.</li><li>More detail: <a href="/docs/providers/synthetic">Synthetic</a></li><li><strong>Moonshot (Kimi K2)</strong>: config is auto-written.</li><li><strong>Kimi Coding</strong>: config is auto-written.</li><li>More detail: <a href="/docs/providers/moonshot">Moonshot AI (Kimi + Kimi Coding)</a></li><li><strong>Skip</strong>: no auth configured yet.</li><li>Pick a default model from detected options (or enter provider/model manually).</li><li>Wizard runs a model check and warns if the configured model is unknown or missing auth.</li><li>OAuth credentials live in <code>~/.opensoul/credentials/oauth.json</code>; auth profiles live in <code>~/.opensoul/agents/&lt;agentId&gt;/agent/auth-profiles.json</code> (API keys + OAuth).</li><li>More detail: <a href="/docs/concepts/oauth">/concepts/oauth</a></li></ul><blockquote><p><strong>Note:</strong> Headless/server tip: complete OAuth on a machine with a browser, then copy <code>~/.opensoul/credentials/oauth.json</code> (or <code>$OPENSOUL_STATE_DIR/credentials/oauth.json</code>) to the gateway host.</p></blockquote><h3 id="workspace" tabindex="-1"><a class="header-anchor" href="#workspace">#</a> Workspace</h3><ul><li>Default <code>~/.opensoul/workspace</code> (configurable).</li><li>Seeds the workspace files needed for the agent bootstrap ritual.</li><li>Full workspace layout + backup guide: <a href="/docs/concepts/agent-workspace">Agent workspace</a></li></ul><h3 id="gateway" tabindex="-1"><a class="header-anchor" href="#gateway">#</a> Gateway</h3><ul><li>Port, bind, auth mode, tailscale exposure.</li><li>Auth recommendation: keep <strong>Token</strong> even for loopback so local WS clients must authenticate.</li><li>Disable auth only if you fully trust every local process.</li><li>Non‑loopback binds still require auth.</li></ul><h3 id="channels" tabindex="-1"><a class="header-anchor" href="#channels">#</a> Channels</h3><ul><li><a href="/docs/channels/whatsapp">WhatsApp</a>: optional QR login.</li><li><a href="/docs/channels/telegram">Telegram</a>: bot token.</li><li><a href="/docs/channels/discord">Discord</a>: bot token.</li><li><a href="/docs/channels/googlechat">Google Chat</a>: service account JSON + webhook audience.</li><li><a href="/docs/channels/mattermost">Mattermost</a> (plugin): bot token + base URL.</li><li><a href="/docs/channels/signal">Signal</a>: optional <code>signal-cli</code> install + account config.</li><li><a href="/docs/channels/bluebubbles">BlueBubbles</a>: <strong>recommended for iMessage</strong>; server URL + password + webhook.</li><li><a href="/docs/channels/imessage">iMessage</a>: legacy <code>imsg</code> CLI path + DB access.</li><li>DM security: default is pairing. First DM sends a code; approve via <code>opensoul pairing approve &lt;channel&gt; &lt;code&gt;</code> or use allowlists.</li></ul><h3 id="daemon-install" tabindex="-1"><a class="header-anchor" href="#daemon-install">#</a> Daemon install</h3><ul><li>macOS: LaunchAgent <ul><li>Requires a logged-in user session; for headless, use a custom LaunchDaemon (not shipped).</li></ul></li><li>Linux (and Windows via WSL2): systemd user unit <ul><li>Wizard attempts to enable lingering via <code>loginctl enable-linger &lt;user&gt;</code> so the Gateway stays up after logout.</li><li>May prompt for sudo (writes <code>/var/lib/systemd/linger</code>); it tries without sudo first.</li></ul></li><li><strong>Runtime selection:</strong> Node (recommended; required for WhatsApp/Telegram). Bun is <strong>not recommended</strong>.</li></ul><h3 id="health-check" tabindex="-1"><a class="header-anchor" href="#health-check">#</a> Health check</h3><ul><li>Starts the Gateway (if needed) and runs <code>opensoul health</code>.</li><li>Tip: <code>opensoul status --deep</code> adds gateway health probes to status output (requires a reachable gateway).</li></ul><h3 id="skills-recommended" tabindex="-1"><a class="header-anchor" href="#skills-recommended">#</a> Skills (recommended)</h3><ul><li>Reads the available skills and checks requirements.</li><li>Lets you choose a node manager: <strong>npm / pnpm</strong> (bun not recommended).</li><li>Installs optional dependencies (some use Homebrew on macOS).</li></ul>',20)])])}const g=o(s,[["render",n]]);export{p as __pageData,g as default};
